$gpid = $ThisService.ProcessId

$IncludeEstablished = $false

$IsWin = (-not (Test-Path Variable:IsWindows)) -or $IsWindows

function Get-ProcessParentPairs {
    if (-not $IsWin) {
        & ps -e -o pid=,ppid= 2>$null | ForEach-Object {
            $f = $_.Trim() -split '\s+'
            if ($f.Count -ge 2) {
                [pscustomobject]@{ ProcId = [int]$f[0]; ParentId = [int]$f[1] }
            }
        }
        return
    }

    $pairs = @()
    if ($PSVersionTable.PSVersion.Major -ge 6) {
        $pairs = @(
            Get-Process -ErrorAction SilentlyContinue | ForEach-Object {
                $parentId = $null
                try { if ($_.Parent) { $parentId = [int]$_.Parent.Id } } catch { }
                if ($null -ne $parentId) {
                    [pscustomobject]@{ ProcId = [int]$_.Id; ParentId = $parentId }
                }
            }
        )
    }

    if ($pairs.Count -eq 0) {
        try {
            $pairs = @(
                Get-CimInstance Win32_Process -ErrorAction Stop | ForEach-Object {
                    [pscustomobject]@{ ProcId = [int]$_.ProcessId; ParentId = [int]$_.ParentProcessId }
                }
            )
        }
        catch {
            Write-Warning "Could not enumerate the process tree (Process.Parent unavailable and CIM failed); reporting the root PID only."
        }
    }

    $pairs
}

function Get-DescendantIds {
    param([int]$RootId, $Pairs)

    $byParent = @{}
    foreach ($p in $Pairs) {
        if (-not $byParent.ContainsKey($p.ParentId)) {
            $byParent[$p.ParentId] = New-Object System.Collections.Generic.List[int]
        }
        $byParent[$p.ParentId].Add($p.ProcId)
    }

    $seen  = New-Object System.Collections.Generic.HashSet[int]
    $queue = New-Object System.Collections.Generic.Queue[int]
    $queue.Enqueue($RootId)
    while ($queue.Count -gt 0) {
        $cur = $queue.Dequeue()
        if ($byParent.ContainsKey($cur)) {
            foreach ($c in $byParent[$cur]) {
                if ($seen.Add($c)) { $queue.Enqueue($c) }
            }
        }
    }
    $seen
}

function Parse-Netstat {
    param([string[]]$Lines, $IdSet, [switch]$Windows, [switch]$AllStates)

    foreach ($line in $Lines) {
        $cols = $line.Trim() -split '\s+'
        if ($cols.Count -lt 4) { continue }

        if ($Windows) {
            $proto = $cols[0].ToUpper()
            if ($proto -ne 'TCP' -and $proto -ne 'UDP') { continue }
            $local  = $cols[1]
            $procId = 0
            if (-not [int]::TryParse($cols[-1], [ref]$procId)) { continue }
            if ($proto -eq 'TCP' -and -not $AllStates -and $cols[3] -ne 'LISTENING') { continue }
        }
        else {
            if     ($cols[0] -like 'tcp*') { $proto = 'TCP' }
            elseif ($cols[0] -like 'udp*') { $proto = 'UDP' }
            else   { continue }
            $local  = $cols[3]
            $pidTok = $cols | Where-Object { $_ -match '^\d+/' } | Select-Object -First 1
            if (-not $pidTok) { continue }
            $procId = [int]($pidTok.Split('/')[0])
        }

        if (-not $IdSet.Contains([int]$procId)) { continue }

        $port = ($local -split ':')[-1]
        $addr = $local.Substring(0, [Math]::Max(0, $local.LastIndexOf(':')))
        [pscustomobject]@{
            Protocol     = $proto
            LocalPort    = [int]$port
            LocalAddress = $addr
            PID          = [int]$procId
            Process      = (Get-Process -Id $procId -ErrorAction SilentlyContinue).ProcessName
        }
    }
}

function Get-PortsWindows {
    param($IdSet, [bool]$IncludeEstablished)

    if (Get-Command Get-NetTCPConnection -ErrorAction SilentlyContinue) {
        $tcp = if ($IncludeEstablished) { Get-NetTCPConnection -ErrorAction SilentlyContinue }
               else                     { Get-NetTCPConnection -State Listen -ErrorAction SilentlyContinue }

        $tcp | Where-Object { $_.OwningProcess -and $IdSet.Contains([int]$_.OwningProcess) } |
            ForEach-Object {
                [pscustomobject]@{
                    Protocol     = 'TCP'
                    LocalPort    = [int]$_.LocalPort
                    LocalAddress = $_.LocalAddress
                    PID          = [int]$_.OwningProcess
                    Process      = (Get-Process -Id $_.OwningProcess -ErrorAction SilentlyContinue).ProcessName
                }
            }

        Get-NetUDPEndpoint -ErrorAction SilentlyContinue |
            Where-Object { $_.OwningProcess -and $IdSet.Contains([int]$_.OwningProcess) } |
            ForEach-Object {
                [pscustomobject]@{
                    Protocol     = 'UDP'
                    LocalPort    = [int]$_.LocalPort
                    LocalAddress = $_.LocalAddress
                    PID          = [int]$_.OwningProcess
                    Process      = (Get-Process -Id $_.OwningProcess -ErrorAction SilentlyContinue).ProcessName
                }
            }
    }
    else {
        Parse-Netstat -Lines (& netstat -ano) -IdSet $IdSet -Windows -AllStates:$IncludeEstablished
    }
}

function Get-PortsLinux {
    param($IdSet, [bool]$IncludeEstablished)

    if (Get-Command ss -ErrorAction SilentlyContinue) {
        $ssArgs = if ($IncludeEstablished) { '-tuanp' } else { '-tulnp' }
        foreach ($line in (& ss $ssArgs 2>$null)) {
            $cols = $line.Trim() -split '\s+'
            if ($cols.Count -lt 5)                { continue }
            if ($cols[0] -notmatch '^(tcp|udp)$') { continue }
            $proto = $cols[0].ToUpper()
            $local = $cols[4]
            $port  = ($local -split ':')[-1]
            $addr  = $local.Substring(0, [Math]::Max(0, $local.LastIndexOf(':')))
            foreach ($m in [regex]::Matches($line, 'pid=(\d+)')) {
                $procId = [int]$m.Groups[1].Value
                if ($IdSet.Contains($procId)) {
                    [pscustomobject]@{
                        Protocol     = $proto
                        LocalPort    = [int]$port
                        LocalAddress = $addr
                        PID          = $procId
                        Process      = (Get-Process -Id $procId -ErrorAction SilentlyContinue).ProcessName
                    }
                }
            }
        }
    }
    elseif (Get-Command netstat -ErrorAction SilentlyContinue) {
        $nsArgs = if ($IncludeEstablished) { '-tuanp' } else { '-tulnp' }
        Parse-Netstat -Lines (& netstat $nsArgs 2>$null) -IdSet $IdSet
    }
    else {
        Write-Warning "Neither 'ss' nor 'netstat' found. Install iproute2 (ss) or net-tools (netstat)."
    }
}

function Get-ListeningPorts {
    param($Ids, [bool]$IncludeEstablished)

    if ($Ids -is [System.Collections.Generic.HashSet[int]]) {
        $idSet = $Ids
    }
    else {
        $idSet = New-Object System.Collections.Generic.HashSet[int]
        foreach ($i in $Ids) { [void]$idSet.Add([int]$i) }
    }

    if ($IsWin) { Get-PortsWindows -IdSet $idSet -IncludeEstablished $IncludeEstablished }
    else        { Get-PortsLinux   -IdSet $idSet -IncludeEstablished $IncludeEstablished }
}

$pairs     = Get-ProcessParentPairs
$targetIds = New-Object System.Collections.Generic.HashSet[int]
[void]$targetIds.Add([int]$gpid)
foreach ($d in (Get-DescendantIds -RootId ([int]$gpid) -Pairs $pairs)) { [void]$targetIds.Add($d) }

$scope = if ($IncludeEstablished) { 'listening + established' } else { 'listening' }
Write-Host "Ports ($scope) for PID $gpid and its child processes [$($targetIds.Count) process(es)]:"

$ports = Get-ListeningPorts -Ids $targetIds -IncludeEstablished $IncludeEstablished |
         Sort-Object Protocol, LocalPort, PID -Unique

if ($ports) {
    $rows = foreach ($p in $ports) {
        $addr = [string]$p.LocalAddress
        if ($addr.Contains(':') -and -not $addr.StartsWith('[')) { $addr = "[$addr]" }
        [pscustomobject]@{
            Protocol        = $p.Protocol
            'Local Address' = $addr + ':' + [string]$p.LocalPort
            PID             = [string]$p.PID
            Process         = $p.Process
        }
    }

    $columns = 'Protocol', 'Local Address', 'PID', 'Process'

    $width = @{}
    foreach ($c in $columns) {
        $cellMax = ($rows | ForEach-Object { ([string]$_.$c).Length } | Measure-Object -Maximum).Maximum
        $width[$c] = [Math]::Max($c.Length, [int]$cellMax)
    }

    $headerCells = foreach ($c in $columns) { $c.PadRight($width[$c]) }
    Write-Host (($headerCells -join '  ').TrimEnd())

    $sepCells = foreach ($c in $columns) { '-' * $width[$c] }
    Write-Host ($sepCells -join '  ')

    foreach ($row in $rows) {
        $cells = foreach ($c in $columns) { ([string]$row.$c).PadRight($width[$c]) }
        Write-Host (($cells -join '  ').TrimEnd())
    }
}
else {
    Write-Host "  (no matching ports found)"
}
